#include "tls_config.h"
#include "config.h"

WiFiClientSecure _secureClient;

// Embed your root CA here or load from SPIFFS
const char* _rootCA = R"EOF(
-----BEGIN CERTIFICATE-----
MIIFazCCA1OgAwIBAgIRAIIQz7DSQONZRGPgu2OCiwAwDQYJKoZIhvcNAQELBQAw
... (paste your CA cert)
-----END CERTIFICATE-----
)EOF";

void tls_config_setup() {
    _secureClient.setCACert(_rootCA);
    // Uncomment for mutual TLS:
    // _secureClient.setCertificate(clientCert);
    // _secureClient.setPrivateKey(clientKey);
    Serial.println("[tls] Secure client configured");
}

WiFiClientSecure& tls_get_client() { return _secureClient; }
